sql:
SELECT SUM(quantity_available) AS total_products
FROM product_sizes
WHERE size_id = (SELECT size_id FROM sizes WHERE size_label = 'M');

SELECT SUM(quantity_available) AS total_stock
FROM product_sizes
WHERE product_id = 0;

external_knowledge:
- "holds the crown" metaphorically indicates the category with the highest value;
- "most expensive in its average price" refers to the category with the highest average price;
- "among its peers" describes the comparison between different categories.

sql:
SELECT size_id, SUM(quantity_available) AS total_quantity_available
FROM product_sizes
GROUP BY size_id;

SELECT size_label
FROM sizes
WHERE bust > (SELECT AVG(bust) FROM sizes);

SELECT COUNT(*)
FROM returns
WHERE return_date BETWEEN '2023-01-01' AND '2023-01-31';

SELECT color
FROM products
WHERE date_added >= DATE('now', '-1 month');
